// ============================================================
// Locatiebepaling: tijd-gevensterde argmax met hysteresis
// ============================================================
// Per speler houden we per paal recente RSSI-samples (met timestamp) bij.
// Samples ouder dan VENSTER_MS vervallen, zodat een verlaten paal vanzelf
// uit beeld raakt (geen 'kleven' meer aan een oude sterke meting).
// De speler staat bij de paal met het sterkste recente gemiddelde (argmax);
// wisselen gebeurt pas als die duidelijk sterker is dan de huidige paal.

// --- TUNING (pas aan na veldtest) ---
const VENSTER_MS     = 5500;  // alleen samples jonger dan dit tellen mee
const MAX_SAMPLES    = 65;     // max bewaarde samples per paal
const HYSTERESE_DBM  = 25;     // nieuwe paal moet huidige met >= dit verslaan
const MIN_SAMPLES    = 1;     // min. recente samples om kandidaat te zijn

// --- 0. SMOELENBOEK ---
const spelersLijst = global.get("spelersLijst") || {};
const ruweMac = msg.payload.mac;
const spelerNaam = spelersLijst[ruweMac];
if (!spelerNaam) return null; // Onbekende beacon negeren
const gepauzeerd = global.get("gespauzeerdePlayers") || {};
if (gepauzeerd[spelerNaam] === true) return null;

const paal = msg.payload.paal;
const rssi = msg.payload.rssi;
const nu = Date.now();

// --- 1. GEHEUGEN ---
let geschiedenis = context.get("geschiedenis") || {};
let spelerLocaties = global.get("spelerLocaties") || {};

if (!geschiedenis[spelerNaam] || !geschiedenis[spelerNaam].samples) {
    geschiedenis[spelerNaam] = { huidigePaal: null, samples: {} };
}
let g = geschiedenis[spelerNaam];

// --- 2. NIEUWE SAMPLE + PRUNE ---
if (!g.samples[paal]) g.samples[paal] = [];
g.samples[paal].push({ rssi: rssi, ts: nu });

for (const p in g.samples) {
    // verouderde samples weggooien
    g.samples[p] = g.samples[p].filter(s => (nu - s.ts) <= VENSTER_MS);
    // lengte begrenzen (laatste MAX_SAMPLES houden)
    if (g.samples[p].length > MAX_SAMPLES) {
        g.samples[p] = g.samples[p].slice(-MAX_SAMPLES);
    }
    // lege palen verwijderen zodat ze geen kandidaat meer zijn
    if (g.samples[p].length === 0) delete g.samples[p];
}

// --- 3. GEMIDDELDE RSSI PER PAAL (recente samples) ---
function gem(arr) {
    return arr.reduce((a, b) => a + b.rssi, 0) / arr.length;
}
let gemiddelden = {};
for (const p in g.samples) {
    gemiddelden[p] = gem(g.samples[p]);
}

// --- 4. ARGMAX: sterkste paal met genoeg recente samples ---
let bestePaal = null;
let besteRssi = -Infinity;
for (const p in g.samples) {
    if (g.samples[p].length < MIN_SAMPLES) continue;
    if (gemiddelden[p] > besteRssi) {
        besteRssi = gemiddelden[p];
        bestePaal = parseInt(p, 10);
    }
}

// --- 5. BESLISSING MET HYSTERESIS ---
const vorigePaal = g.huidigePaal;
if (bestePaal !== null) {
    if (vorigePaal === null || vorigePaal === undefined) {
        // eerste lokalisatie van deze speler
        g.huidigePaal = bestePaal;
    } else if (!(vorigePaal in gemiddelden)) {
        // huidige paal heeft geen recente data meer -> direct loslaten
        g.huidigePaal = bestePaal;
    } else if (bestePaal !== vorigePaal &&
               gemiddelden[bestePaal] > gemiddelden[vorigePaal] + HYSTERESE_DBM) {
        // nieuwe paal duidelijk sterker -> wisselen
        g.huidigePaal = bestePaal;
    }
}

// Beweging-event ALLEEN bij een echte wissel (niet bij eerste lokalisatie),
// zodat het puntensysteem geen levensuur toekent op de allereerste detectie.
let bewegingEvent = null;
if (g.huidigePaal !== vorigePaal &&
    vorigePaal !== null && vorigePaal !== undefined) {
    bewegingEvent = { payload: { speler: spelerNaam, vanPaal: vorigePaal, naarPaal: g.huidigePaal } };
}

context.set("geschiedenis", geschiedenis);

// --- 6. CENTRALE WAARHEID ---
if (g.huidigePaal !== null && g.huidigePaal !== undefined) {
    spelerLocaties[spelerNaam] = g.huidigePaal;
    global.set("spelerLocaties", spelerLocaties);
}

// --- 7. TABELDATA (incl. levensuren/levensdagen uit flow 04) ---
const stats = global.get("spelerStats") || {};
let tabelData = [];
for (let speler in spelerLocaties) {
    const totaalUren = (stats[speler] && stats[speler].totaalUren) || 0;
    const huidige = spelerLocaties[speler];
    // toon het gemiddelde RSSI over het venster voor de actieve paal
    let rssiTekst = "?";
    const sg = geschiedenis[speler] && geschiedenis[speler].samples;
    if (sg && sg[huidige] && sg[huidige].length) {
        rssiTekst = Math.round(gem(sg[huidige]));
    }
    tabelData.push({
        "Speler": speler,
        "Locatie": "Paal " + huidige,
        "RSSI": rssiTekst,
        "Levensdagen": Math.floor(totaalUren / 24),
        "Levensuren": totaalUren % 24,
        "Achterstand": (stats[speler] && stats[speler].achterstand) || 0
    });
}

msg.payload = tabelData;
// Output 1: radar-tabel  |  Output 2: beweging-event naar puntensysteem
return [msg, bewegingEvent];

// Detectie binnen via plaatjes/data: {paal, mac, rssi}
const nu = Date.now();
const d = msg.payload;
if (!d || d.paal === undefined || !d.mac) { return null; }

let macSeen = global.get("status_lastSeenMac") || {};
let paalSeen = global.get("status_lastSeenPaal") || {};

macSeen[d.mac] = nu;
paalSeen[d.paal] = nu;

global.set("status_lastSeenMac", macSeen);
global.set("status_lastSeenPaal", paalSeen);
global.set("status_lastDataTs", nu);

return msg;

// Spel gestopt: stop evaluatie en toon gestopt-status
if (global.get("spelToestand") === "gestopt") {
    return [
        { payload: [] },
        { payload: [] },
        { payload: [{ Code: "-", Niveau: "INFO", Onderdeel: "-", Omschrijving: "Spel is gestopt" }] },
        { payload: "GESTOPT — spel is beëindigd" }
    ];
}
// === Spelstatus evaluatie ===
const nu = Date.now();

// Instelbare drempels
const SPELER_TIMEOUT_MS = 15000;
const SLAVE_STALE_MS = 60000;
const GEEN_DATA_MS = 10000;

// Bronnen
const spelersLijst = global.get("spelersLijst") || {};
const paaltjesLijst = global.get("paaltjesLijst") || [];
const macSeen = global.get("status_lastSeenMac") || {};
const paalSeen = global.get("status_lastSeenPaal") || {};
const lastDataTs = global.get("status_lastDataTs") || 0;
const batterijPaal = global.get("status_batterijPaal") || {};
const toonBatterij = global.get("status_toonBatterij") === true;
const override = global.get("status_override") === true;

let fouten = [];

// 1. SPELERS
let spelersTabel = [];
for (const mac in spelersLijst) {
    const naam = spelersLijst[mac];
    const t = macSeen[mac];
    let status, ouderdom;
    if (!t) {
        status = "NIET GEZIEN";
        ouderdom = "-";
        fouten.push({ Code: "ST-001", Niveau: "FOUT", Onderdeel: naam, Omschrijving: "Speler nog niet gedetecteerd in het veld" });
    } else if (nu - t > SPELER_TIMEOUT_MS) {
        ouderdom = (nu - t > 300000) ? ">300s" : Math.round((nu - t) / 1000) + "s";
        status = "VERLOREN";
        fouten.push({ Code: "ST-001", Niveau: "FOUT", Onderdeel: naam, Omschrijving: "Speler al " + ouderdom + " niet meer gezien" });
    } else {
        ouderdom = (nu - t > 300000) ? ">300s" : Math.round((nu - t) / 1000) + "s";
        status = "OK";
    }
    spelersTabel.push({ Speler: naam, Status: status, "Laatst gezien": ouderdom });
}

// 2. SLAVES / PALEN
let palenTabel = [];
for (const paal of paaltjesLijst) {
    const t = paalSeen[paal];
    let status, ouderdom;
    if (!t) {
        status = "GEEN CONTACT";
        ouderdom = "-";
        fouten.push({ Code: "ST-002", Niveau: "WAARSCHUWING", Onderdeel: "Paal " + paal, Omschrijving: "Slave heeft nog geen data gestuurd" });
    } else if (nu - t > SLAVE_STALE_MS) {
        ouderdom = (nu - t > 300000) ? ">300s" : Math.round((nu - t) / 1000) + "s";
        status = "VEROUDERD";
        fouten.push({ Code: "ST-002", Niveau: "WAARSCHUWING", Onderdeel: "Paal " + paal, Omschrijving: "Slave al " + ouderdom + " stil" });
    } else {
        ouderdom = (nu - t > 300000) ? ">300s" : Math.round((nu - t) / 1000) + "s";
        status = "OK";
    }
    // Batterij-kolom: gevuld als toggle aan staat, anders "-"
    let batterijTekst = "-";
    if (toonBatterij) {
        const b = batterijPaal[paal];
        batterijTekst = (b && typeof b.volt === "number")
            ? b.volt.toFixed(2) + " V"
            : "?";
    }
    palenTabel.push({ Paal: paal, Status: status, "Laatst gezien": ouderdom, "Batterij": batterijTekst });
}

// 3. DATASTROOM
if (lastDataTs === 0) {
    fouten.push({ Code: "ST-003", Niveau: "FOUT", Onderdeel: "Datastroom", Omschrijving: "Nog geen enkel bericht ontvangen op plaatjes/data" });
} else if (nu - lastDataTs > GEEN_DATA_MS) {
    fouten.push({ Code: "ST-003", Niveau: "FOUT", Onderdeel: "Datastroom", Omschrijving: "Al " + Math.round((nu - lastDataTs) / 1000) + "s geen data - controleer master/bridge" });
}

// 4. ONBEKENDE BEACONS (informatief)
for (const mac in macSeen) {
    if (!spelersLijst[mac] && (nu - macSeen[mac] < SPELER_TIMEOUT_MS)) {
        fouten.push({ Code: "ST-004", Niveau: "INFO", Onderdeel: mac, Omschrijving: "Onbekende beacon gedetecteerd (niet geregistreerd)" });
    }
}

// SAMENVATTING
const aantalFout = fouten.filter(f => f.Niveau === "FOUT").length;
const spelOk = aantalFout === 0 && spelersTabel.length > 0 && palenTabel.length > 0;

global.set("status_ok", spelOk);
global.set("status_fouten", fouten);

let statusTekst;
if (spelOk) {
    statusTekst = override
        ? "GO - spelstatus OK (override actief)"
        : "GO - spelstatus OK, klaar om te starten";
} else if (override) {
    statusTekst = "NO-GO - " + aantalFout + " fout(en) - OVERRIDE actief, Start spel mogelijk";
} else {
    statusTekst = "NO-GO - " + aantalFout + " fout(en), zie foutcodes";
}

const foutenTabel = fouten.length > 0
    ? fouten
    : [{ Code: "-", Niveau: "INFO", Onderdeel: "-", Omschrijving: "Geen fouten" }];

return [
    { payload: spelersTabel },
    { payload: palenTabel },
    { payload: foutenTabel },
    { payload: statusTekst }
];

// Verwerk een knop van het Bediening-dashboard
const actie = msg.payload;
let toestand = global.get("spelToestand") || "gestopt";
const statusOk = global.get("status_ok");
const override = global.get("status_override") === true;
let melding = "";

switch (actie) {
    case "start":
        if (toestand === "lopend") {
            melding = "Spel liep al.";
        } else if (statusOk === false && !override) {
            // NO-GO en geen override: weiger te starten
            melding = "NO-GO - kan niet starten. Los fouten op of zet OVERRIDE aan.";
        } else {
            toestand = "lopend";
            if (statusOk === false && override) {
                melding = "Spel GESTART met OVERRIDE - spelstatus was NIET OK";
            } else {
                melding = "Spel gestart.";
            }
        }
        break;
    case "pauzeer":
        if (toestand === "lopend") {
            toestand = "gepauzeerd";
            melding = "Spel gepauzeerd.";
        } else {
            melding = "Pauzeren kan enkel terwijl het spel loopt.";
        }
        break;
    case "hervat":
        if (toestand === "gepauzeerd") {
            toestand = "lopend";
            melding = "Spel hervat.";
        } else {
            melding = "Hervatten kan enkel vanuit pauze.";
        }
        break;
    case "herstart":
        toestand = "lopend";
        melding = "Spel herstart - toestand teruggezet naar het begin.";
        break;
    case "toon":
        melding = "Huidige toestand.";
        break;
    default:
        melding = "Onbekende actie: " + actie;
}

global.set("spelToestand", toestand);

msg.payload = "Toestand: " + toestand.toUpperCase() + "  |  " + melding;
return msg;

// Status-event van de MQTT-in node: bepaal of de broker bereikbaar is.
// node-red zet fill='green' bij 'connected', anders rood/grijs/geel.
const fill = msg.status && msg.status.fill;
const text = (msg.status && msg.status.text) || "";
const connected = (fill === "green")
    || /connected/i.test(text);
return { payload: connected };

// Batterij-regel binnen via plaatjes/data: {paal, batt}
// Tegelijk gebruiken als heartbeat zodat een paal met 0 spelers ook
// als 'levend' geldt in de spelstatus.
const nu = Date.now();
const d = msg.payload;
if (!d || d.paal === undefined || d.batt === undefined) return null;

let batterijPaal = global.get("status_batterijPaal") || {};
batterijPaal[d.paal] = { volt: d.batt, ts: nu };
global.set("status_batterijPaal", batterijPaal);

let paalSeen = global.get("status_lastSeenPaal") || {};
paalSeen[d.paal] = nu;
global.set("status_lastSeenPaal", paalSeen);
global.set("status_lastDataTs", nu);
return null;

// === Puntensysteem: levensuren op de 24-uurs klok (deficit-model) ===
// Inkomend event: { speler, vanPaal, naarPaal }. Zie docs/spel.md.
//  - elk uur VOORUIT = +1 levensuur; 24 levensuren = 1 levensdag
//  - ACHTERUIT = -1 per uur, normaal NIET toegestaan (per speler 'tijdTerug')
//  - score telt alleen tijdens een lopend spel (global.spelToestand)
//  - 'achterstand' = hoeveel uur de speler illegaal onder zijn hoogste legale
//    positie zit. Vooruit haalt eerst die achterstand in voordat er punten
//    bijkomen, zodat terug-en-weer-vooruit geen gratis levensuren oplevert.
//  - Plates-of-Fate regel maxVerplaatsing begrenst de vooruit-stappen per ronde.
const AANTAL_UREN = 24;

const ev = msg.payload;
if (!ev || !ev.speler || ev.vanPaal === undefined || ev.naarPaal === undefined) {
    return null;
}

let stats = global.get("spelerStats") || {};
let s = stats[ev.speler] || {};
if (s.totaalUren === undefined) s.totaalUren = 0;
if (s.tijdTerug === undefined) s.tijdTerug = false;
if (s.achterstand === undefined) s.achterstand = 0;
if (s.verplaatstRonde === undefined) s.verplaatstRonde = 0;

// Alleen scoren tijdens een lopend spel. Anders enkel positie bijwerken.
const toestand = global.get("spelToestand") || "gestopt";
if (toestand !== "lopend") {
    s.huidigePaal = ev.naarPaal;
    stats[ev.speler] = s;
    global.set("spelerStats", stats);
    msg.payload = {
        speler: ev.speler, van: ev.vanPaal, naar: ev.naarPaal,
        richting: "genegeerd", stappen: 0,
        totaalUren: s.totaalUren,
        levensdagen: Math.floor(s.totaalUren / 24),
        levensuren: s.totaalUren % 24,
        achterstand: s.achterstand,
        tijdTerug: s.tijdTerug,
        melding: ev.speler + " bewoog (" + ev.vanPaal + "->" + ev.naarPaal + ") maar spel is " + toestand.toUpperCase() + " - geen levensuren"
    };
    return msg;
}

// Plates-of-Fate effect: speler 'mag niet bewegen' -> beweging telt niet mee.
const _fx = (global.get("spelerEffecten") || {})[ev.speler] || [];
if (_fx.some(e => e.effect === "mag_niet_bewegen")) {
    s.huidigePaal = ev.naarPaal;
    stats[ev.speler] = s;
    global.set("spelerStats", stats);
    msg.payload = {
        speler: ev.speler, van: ev.vanPaal, naar: ev.naarPaal,
        richting: "geblokkeerd", stappen: 0,
        totaalUren: s.totaalUren,
        levensdagen: Math.floor(s.totaalUren / 24),
        levensuren: s.totaalUren % 24,
        achterstand: s.achterstand, tijdTerug: s.tijdTerug,
        melding: ev.speler + " mag niet bewegen (Plates-of-Fate effect) - geen wijziging"
    };
    return msg;
}

// Verplaatsing op de cirkel van AANWEZIGE palen (paaltjesLijst als ring).
// Van de hoogste naar de laagste aanwezige paal telt zo als 1 stap vooruit
// (de cirkel sluit), niet als grote sprong achteruit.
const palen = (global.get("paaltjesLijst") || []).slice().sort((a, b) => a - b);
const N = palen.length;
const iVan = palen.indexOf(ev.vanPaal);
const iNaar = palen.indexOf(ev.naarPaal);
let richting, stappen;
if (N < 2 || iVan < 0 || iNaar < 0) {
    richting = "geen"; stappen = 0;   // onbekende paal -> geen wijziging
} else {
    let vooruit = (((iNaar - iVan) % N) + N) % N;
    let achteruit = N - vooruit;
    if (vooruit === 0) { richting = "geen"; stappen = 0; }
    else if (vooruit <= achteruit) { richting = "vooruit"; stappen = vooruit; }
    else { richting = "achteruit"; stappen = achteruit; }
}

const regels = global.get("pofRegels") || {};
let melding;

if (richting === "vooruit") {
    let toegestaan = stappen;
    let illegaalExtra = 0;
    // Plates-of-Fate: begrens vooruit-verplaatsing per ronde.
    if (regels.maxVerplaatsing !== undefined && regels.maxVerplaatsing !== null) {
        const ruimte = Math.max(0, regels.maxVerplaatsing - s.verplaatstRonde);
        if (toegestaan > ruimte) {
            illegaalExtra = toegestaan - ruimte;
            toegestaan = ruimte;
        }
    }
    // Eerst de achterstand inhalen, dan pas punten toekennen.
    if (toegestaan > 0) {
        if (s.achterstand >= toegestaan) {
            s.achterstand -= toegestaan;
        } else {
            const nieuw = toegestaan - s.achterstand;
            s.achterstand = 0;
            s.totaalUren += nieuw;
        }
        s.verplaatstRonde += toegestaan;
    }
    // Illegale extra (regel-overtreding) -> als achterstand, nooit belonen.
    if (illegaalExtra > 0) {
        s.achterstand += illegaalExtra;
        melding = ev.speler + ": regel max " + regels.maxVerplaatsing + " overschreden, " + illegaalExtra + " uur genegeerd";
    } else {
        melding = ev.speler + " +" + toegestaan + " levensuur(en) (vooruit)";
    }
} else if (richting === "achteruit") {
    if (s.tijdTerug) {
        s.totaalUren = Math.max(0, s.totaalUren - stappen);
        melding = ev.speler + " -" + stappen + " levensuur(en) (terug in de tijd)";
    } else {
        // Illegaal terug: geen aftrek, maar de achterstand groeit zodat de
        // speler eerst weer terug omhoog moet voordat hij punten verdient.
        s.achterstand += stappen;
        melding = ev.speler + " ging achteruit (illegaal) - geen aftrek, achterstand nu " + s.achterstand;
    }
} else {
    melding = ev.speler + " geen netto verplaatsing";
}

s.huidigePaal = ev.naarPaal;
stats[ev.speler] = s;
global.set("spelerStats", stats);

msg.payload = {
    speler: ev.speler, van: ev.vanPaal, naar: ev.naarPaal,
    richting: richting, stappen: stappen,
    totaalUren: s.totaalUren,
    levensdagen: Math.floor(s.totaalUren / 24),
    levensuren: s.totaalUren % 24,
    achterstand: s.achterstand,
    verplaatstRonde: s.verplaatstRonde,
    tijdTerug: s.tijdTerug,
    melding: melding
};
return msg;

// Admin-reset met twee-staps verificatie.
// Stap 1: 'Admin ontgrendelen' moet AAN (global.admin_unlocked).
// Stap 2: een resetknop. Na uitvoeren vergrendelt het paneel weer.
const topic = msg.topic;
const unlocked = global.get("admin_unlocked") === true;

if (!unlocked) {
    msg.payload = "VERGRENDELD - zet eerst 'Admin ontgrendelen' aan (stap 1).";
    return [msg, null];
}

let stats = global.get("spelerStats") || {};
let aantal = 0;
let wat;
let eenheid = "speler(s)";

if (topic === "reset_dagen") {
    for (let naam in stats) {
        const t = stats[naam].totaalUren || 0;
        stats[naam].totaalUren = t % 24;            // dagen weg, uren-rest blijft
        stats[naam].achterstand = 0;
        stats[naam].verplaatstRonde = 0;
        aantal++;
    }
    wat = "Levensdagen";
} else if (topic === "reset_uren") {
    for (let naam in stats) {
        const t = stats[naam].totaalUren || 0;
        stats[naam].totaalUren = Math.floor(t / 24) * 24;  // uren-rest weg, dagen blijven
        stats[naam].achterstand = 0;
        stats[naam].verplaatstRonde = 0;
        aantal++;
    }
    wat = "Levensuren";
} else if (topic === "reset_achterstand") {
    for (let naam in stats) {
        stats[naam].achterstand = 0;
        aantal++;
    }
    wat = "Achterstand";
} else if (topic === "reset_paaleffecten") {
    const bord = global.get("bordStaat") || {};
    aantal = Object.keys(bord).length;
    global.set("bordStaat", {});
    wat = "Paal-effecten"; eenheid = "paal/palen";
} else if (topic === "reset_spelereffecten") {
    const se = global.get("spelerEffecten") || {};
    const we = global.get("wereldEffecten") || [];
    aantal = Object.keys(se).length + we.length;
    global.set("spelerEffecten", {});
    global.set("wereldEffecten", []);
    wat = "Speler- + Wereld-effecten"; eenheid = "effect(en)";
} else {
    msg.payload = "Onbekende reset-actie: " + topic;
    return [msg, null];
}

global.set("spelerStats", stats);
global.set("admin_unlocked", false);   // automatisch hervergrendelen

msg.payload = wat + " gereset (" + aantal + " " + eenheid + "). Paneel weer vergrendeld.";
return [msg, { payload: false }];

// Merge events per categorie zodat de drie config-injects elkaar niet overschrijven.
const cat = msg.topic;
let all = global.get("pofEvents") || [];
all = all.filter(e => e.categorie !== cat);
if (Array.isArray(msg.payload)) all = all.concat(msg.payload);
global.set("pofEvents", all);
return null;

// Plates-of-Fate toestandsmachine. Gevoed door de 1s-ticker en de knoppen.
// out1: start CHOOSE (-> Kies event) | out2: start VERIFY (-> Verifieer) | out3: timer-display | out4: trigger uitvoer (-> Voer gevolg uit)
const AANLOOP_S = 5;
const t = msg.topic;
const manueel = global.get("pofManueel") === true;
const lopend = (global.get("spelToestand") || "gestopt") === "lopend";
const disp = (tekst) => ({ payload: tekst });

if (t === "pof_start") {
    global.set("pofActief", true);
    global.set("pofEventenRonde", 0);
    global.set("pofDoelwitDisplay", null);
    if (manueel) {
        global.set("pofFase", "wacht"); global.set("pofTeller", 0);
        return [null, null, disp("Wacht op 'Volgende event'")];
    }
    global.set("pofFase", "aanloop"); global.set("pofTeller", AANLOOP_S);
    return [null, null, disp("Volgend event over: " + AANLOOP_S + "s")];
}
if (t === "pof_stop") {
    global.set("pofActief", false); global.set("pofFase", "idle");
    return [null, null, disp("POF gestopt")];
}
if (t === "pof_volgende") {
    if (global.get("pofActief") === true && lopend) {
        global.set("pofFase", "bezig");
        return [{ start: true }, null, disp("Event gekozen...")];
    }
    return null;
}
if (t === "pof_controle") {
    const fa = global.get("pofFase");
    if (global.get("pofActief") === true && lopend) {
        if (fa === "wacht_uitvoer") {
            const pending = global.get("pofPendingEvent");
            if (!pending) return null;
            global.set("pofPendingEvent", null);
            const doel = pending.doelwit || [];
            const dTekst = doel.length ? doel.join(", ") : "niemand";
            global.set("pofDoelwitDisplay", "Doelwit: " + dTekst);
            global.set("pofFase", "wacht_controle");
            return [null, null, disp("Doelwit: " + dTekst), pending];
        }
        if (fa === "wacht_controle") {
            global.set("pofFase", "bezig");
            return [null, { verify: true }, disp("Controle...")];
        }
    }
    return null;
}

// tick (alleen tijdens een lopend spel met actieve engine)
if (global.get("pofActief") !== true || !lopend) return null;
let fase = global.get("pofFase") || "idle";
let teller = global.get("pofTeller") || 0;

if (fase === "aanloop") {
    teller--;
    if (teller <= 0) { global.set("pofFase", "bezig"); return [{ start: true }, null, disp("Event gekozen...")]; }
    global.set("pofTeller", teller);
    return [null, null, disp("Volgend event over: " + teller + "s")];
}
if (fase === "reactie") {
    teller--;
    if (teller <= 0) { global.set("pofFase", "bezig"); return [null, { verify: true }, disp("Controle...")]; }
    global.set("pofTeller", teller);
    return [null, null, disp("Reactietijd: " + teller + "s")];
}
if (fase === "wacht_controle") {
    const dTekst = global.get("pofDoelwitDisplay") || "Wacht op controle-knop";
    return [null, null, disp(dTekst)];
}
if (fase === "wacht_uitvoer") {
    return [null, null, disp("Wacht op controle (doelwit tonen)")];
}
if (fase === "wacht") {
    return [null, null, disp("Wacht op 'Volgende event'")];
}
return null;

// CHOOSE: kies event, rol eventueel getal en vul 'x' in de tekst.
// out1: chain -> Verouder | out2: audio | out3: Huidig event-display | out4: events-teller-display
const events = global.get("pofEvents") || [];
const categorie = msg.categorie || null;
let pool = categorie ? events.filter(e => e.categorie === categorie) : events;
if (!pool.length) { node.warn("Geen pofEvents" + (categorie ? " voor " + categorie : "")); return null; }

const OPTIE={enkel:[1,1],laag:[1,3],midden:[1,6],hoog:[3,10]};
function rol(o){const r=OPTIE[o]||[1,1];return r[0]+Math.floor(Math.random()*(r[1]-r[0]+1));}

const event = pool[Math.floor(Math.random() * pool.length)];
let tekst = event.tekst;
let getalWaarde = null;
if (event.getal) {
    getalWaarde = rol(event.getal);
    tekst = tekst.replace(/\bx\b/g, getalWaarde);   // vervang losse 'x' door het getal
}

const huidig = Object.assign({}, event, { tekstIngevuld: tekst, getalWaarde: getalWaarde });
global.set("pofHuidigEvent", huidig);
global.set("pofEventenRonde", (global.get("pofEventenRonde") || 0) + 1);

msg.event = event;
msg.getalWaarde = getalWaarde;
const audio = { payload: { fase: "event", tekst: tekst, prioriteit: "normaal" } };
const display = { payload: event.naam + " - " + tekst };
const teller = { payload: "Events deze ronde: " + global.get("pofEventenRonde") };
return [msg, audio, display, teller];

// Kies doelwitten + snapshot beginposities voor de controle.
const event = msg.event;
const d = event.doelwit || { type: "geen" };
const OPTIE={enkel:[1,1],laag:[1,3],midden:[1,6],hoog:[3,10]};
function rol(o){const r=OPTIE[o]||[1,1];return r[0]+Math.floor(Math.random()*(r[1]-r[0]+1));}
function steekproef(arr,n){const k=arr.slice(),u=[];while(u.length<n&&k.length)u.push(k.splice(Math.floor(Math.random()*k.length),1)[0]);return u;}

// aantal kan een optie-string zijn ("enkel"/"laag"/...) of een vast getal.
let aantal = (typeof d.aantal === "string") ? rol(d.aantal) : (d.aantal || 1);

let doelwit = [];
if (d.type === "speler") {
    const lijst = global.get("spelersLijst") || {};
    let namen = Object.keys(lijst).map(k => lijst[k]);
    const _gp = global.get("gespauzeerdePlayers") || {};
    namen = namen.filter(n => !_gp[n]);
    if (d.selectie === "rang") {
        const stats = global.get("spelerStats") || {};
        const w = (naam) => { const s = stats[naam] || {}; return d.veld === "achterstand" ? (s.achterstand||0) : (s.totaalUren||0); };
        namen.sort((a,b) => d.richting === "laagste" ? w(a)-w(b) : w(b)-w(a));
        doelwit = namen.slice(0, aantal);
    } else if (d.selectie === "alle") { doelwit = namen; }
    else { doelwit = steekproef(namen, aantal); }
} else if (d.type === "uur") {
    let palen = (global.get("paaltjesLijst")||[]).slice();
    if (d.selectie === "rang") {
        const loc = global.get("spelerLocaties")||{};
        const bez = (u)=>Object.keys(loc).filter(n=>loc[n]===u).length;
        const w = (u)=> d.veld==="bezetting"? bez(u): u;
        palen.sort((a,b)=> d.richting==="laagste"? w(a)-w(b): w(b)-w(a));
        doelwit = palen.slice(0, aantal);
    } else if (d.selectie === "alle") { doelwit = palen; }
    else { doelwit = steekproef(palen, aantal); }
}
msg.doelwit = doelwit;

// Snapshot beginposities van ALLE spelers (niet-doelwit moet stil blijven).
const loc = global.get("spelerLocaties") || {};
const spelers = global.get("spelersLijst") || {};
let startPosities = {};
for (const mac in spelers) { const naam = spelers[mac]; startPosities[naam] = (loc[naam] !== undefined ? loc[naam] : null); }
global.set("pofVerificatie", {
    voorwaarde: event.voorwaarde || "geen",
    getal: msg.getalWaarde,
    doelwit: doelwit,
    startPosities: startPosities
});

let tekst;
if (!doelwit.length) tekst = "Dit raakt niemand in het bijzonder.";
else if (d.type === "uur") tekst = "Getroffen uren: " + doelwit.join(", ") + ".";
else tekst = "Getroffen spelers: " + doelwit.join(", ") + ".";
const audio = { payload: { fase: "doelwit", tekst: tekst, prioriteit: "normaal" } };
// Typewriter-duur: elke naam heeft 1.6s animatietijd + 1.5s buffer na de laatste
const typewriterDuur = Math.max(1500, doelwit.length * 1600 + 1500);
msg.delay = typewriterDuur;
const twMsg = { payload: { actief: true, eventNaam: event.naam, getalWaarde: msg.getalWaarde || null, doelwit: doelwit } };
const manueel = global.get("pofManueel") === true;
if (manueel) {
    global.set("pofPendingEvent", msg);
    global.set("pofFase", "wacht_uitvoer");
    global.set("pofTeller", 0);
    return [null, audio, twMsg, twMsg];
}
return [msg, audio, twMsg, twMsg];

// Voer gevolgen uit (commando/score/effect/geen). Start daarna de reactietijd.
const event = msg.event;
const doelwit = msg.doelwit || [];
const gevolgen = event.gevolgen || [];
let stats = global.get("spelerStats") || {};
let bord = global.get("bordStaat") || {};
let se = global.get("spelerEffecten") || {};
let we = global.get("wereldEffecten") || [];
function doelUren(){ if(event.doelwit&&event.doelwit.type==="uur")return doelwit;
  if(event.doelwit&&event.doelwit.type==="speler")return doelwit.map(n=>stats[n]&&stats[n].huidigePaal).filter(p=>p!=null); return []; }
let nextId = Date.now();
function maakEffect(g){ return {id:"fx"+(nextId++),effect:g.effect,naam:g.naam||(event&&event.tag)||g.effect,resterendeRondes:g.duurRondes||1,data:g.data||{}}; }

let commandos = [];
for (const g of gevolgen) {
  if (g.type === "commando") { for (const p of doelUren()) commandos.push({ payload: { paal: p, actie: g.actie } }); }
  else if (g.type === "score") { for (const n of doelwit){ let s=stats[n]||{totaalUren:0}; if(s.totaalUren===undefined)s.totaalUren=0; s.totaalUren=Math.max(0,s.totaalUren+(g.delta||0)); stats[n]=s; } }
  else if (g.type === "effect") {
     if (g.niveau==="wereld") we.push(maakEffect(g));
     else if (g.niveau==="speler") for(const n of doelwit){(se[n]=se[n]||[]).push(maakEffect(g));}
     else if (g.niveau==="uur") for(const u of doelUren()){bord[u]=bord[u]||{effecten:[]};bord[u].effecten.push(maakEffect(g));}
     else node.warn("effect zonder geldig niveau");
  }
  else if (g.type === "geen") { /* geen neveneffect */ }
  else node.warn("Onbekend gevolg-type: " + g.type);
}
global.set("spelerStats",stats); global.set("bordStaat",bord); global.set("spelerEffecten",se); global.set("wereldEffecten",we);

// Start de reactietijd (zichtbaar afgeteld door de Engine tick). events_sneller halveert.
let reactie = event.reactietijd_s || 10;
if (we.some(e => e.effect === "events_sneller")) reactie = Math.max(1, Math.round(reactie/2));
// In manueel-modus wachten we op de Controle-knop i.p.v. automatisch af te tellen.
if (global.get("pofManueel") === true) {
    global.set("pofFase", "wacht_controle");
    global.set("pofTeller", 0);
} else {
    global.set("pofFase", "reactie");
    global.set("pofTeller", reactie);
}

return [commandos];

// Tel alle blijvende effecten één ronde af; verwijder afgelopen effecten.
// out1: chain -> Kies doelwit | out2: trigger -> Bouw effecten-tabel
function veroud(arr) {
    return (arr || [])
        .map(e => Object.assign({}, e, { resterendeRondes: e.resterendeRondes - 1 }))
        .filter(e => e.resterendeRondes > 0);
}

let bord = global.get("bordStaat") || {};
for (const uur in bord) {
    bord[uur].effecten = veroud(bord[uur].effecten);
    if (!bord[uur].effecten.length) delete bord[uur];
}
global.set("bordStaat", bord);

let se = global.get("spelerEffecten") || {};
for (const naam in se) {
    se[naam] = veroud(se[naam]);
    if (!se[naam].length) delete se[naam];
}
global.set("spelerEffecten", se);

global.set("wereldEffecten", veroud(global.get("wereldEffecten")));

return [msg, { payload: "rebuild" }];

// Plat de drie effect-registers tot tabelrijen voor de Live Radar.
let rijen = [];
const bord = global.get("bordStaat") || {};
for (const uur in bord) {
    for (const e of bord[uur].effecten) {
        rijen.push({ Niveau: "uur", Doel: "Paal " + uur, Effect: e.naam, "Rondes resterend": e.resterendeRondes });
    }
}
const se = global.get("spelerEffecten") || {};
for (const naam in se) {
    for (const e of se[naam]) {
        rijen.push({ Niveau: "speler", Doel: naam, Effect: e.naam, "Rondes resterend": e.resterendeRondes });
    }
}
for (const e of (global.get("wereldEffecten") || [])) {
    rijen.push({ Niveau: "wereld", Doel: "-", Effect: e.naam, "Rondes resterend": e.resterendeRondes });
}
if (!rijen.length) {
    rijen = [{ Niveau: "-", Doel: "-", Effect: "geen actieve effecten", "Rondes resterend": "-" }];
}
msg.payload = rijen;
return msg;

const we = global.get("wereldEffecten") || [];
let rijen = we.map(e => ({ Effect: e.naam, "Rondes resterend": e.resterendeRondes }));
if (!rijen.length) rijen = [{ Effect: "geen actieve wereld-effecten", "Rondes resterend": "-" }];
msg.payload = rijen;
return msg;

// Wis alle blijvende effecten (handig bij testen / herstart van een cyclus).
global.set("bordStaat", {});
global.set("spelerEffecten", {});
global.set("wereldEffecten", []);
msg.payload = "rebuild";
return msg;

// Controleer na de reactietijd of aan de beweging-voorwaarden voldaan is.
const v = global.get("pofVerificatie") || {};
const loc = global.get("spelerLocaties") || {};
const se = global.get("spelerEffecten") || {};
const we = global.get("wereldEffecten") || [];
const bord = global.get("bordStaat") || {};
const palen = (global.get("paaltjesLijst") || []).slice().sort((a, b) => a - b);
const M = palen.length;
function netto(start, eind) {
    if (start == null || eind == null) return null;
    const iVan = palen.indexOf(start), iNaar = palen.indexOf(eind);
    if (M < 2 || iVan < 0 || iNaar < 0) return null;
    const vooruit = (((iNaar - iVan) % M) + M) % M;
    const achteruit = M - vooruit;
    return (vooruit <= achteruit) ? vooruit : -achteruit;  // signed kortste op de ring
}
const doelwitSet = new Set(v.doelwit || []);
const start = v.startPosities || {};
let rijen = [];
for (const naam in start) {
    const n = netto(start[naam], (loc[naam] !== undefined ? loc[naam] : null));
    let status;
    if (n === null) status = "onbekend";
    else if (doelwitSet.has(naam)) {
        if (v.voorwaarde === "min") status = (n >= v.getal) ? "OK" : "TE WEINIG";
        else if (v.voorwaarde === "max") status = (n <= v.getal) ? "OK" : "TE VEEL";
        else status = "OK";
    } else {
        status = (n === 0) ? "OK (stil)" : "BEWOOG (mocht niet)";
    }
    const paalFX = ((bord[loc[naam]] || {}).effecten || []).map(e => e.naam);
    const allFX = [...(se[naam] || []).map(e => e.naam), ...we.map(e => e.naam), ...paalFX];
    const tag = allFX.length ? allFX.join(", ") : "-";
    rijen.push({ Speler: naam, Tag: tag,
                 Verplaatst: (n === null ? "?" : n), Status: status });
}

// Volgende fase: automatisch nieuwe aanloop, of wachten in manueel-modus.
const manueel = global.get("pofManueel") === true;
global.set("pofFase", manueel ? "wacht" : "aanloop");
global.set("pofTeller", manueel ? 0 : 5);

msg.payload = rijen.length ? rijen : [{ Speler:"-", Tag:"-", Verplaatst:"-", Status:"geen spelers" }];
return msg;

const spelersLijst = global.get("spelersLijst") || {};
const gp = global.get("gespauzeerdePlayers") || {};
msg.payload = Object.values(spelersLijst).map(naam => ({
    naam: naam,
    gepauzeerd: gp[naam] === true
}));
return msg;

if (!msg.payload || !msg.payload.speler) return null;
const gp = global.get("gespauzeerdePlayers") || {};
gp[msg.payload.speler] = msg.payload.gepauzeerd;
global.set("gespauzeerdePlayers", gp);
const spelersLijst = global.get("spelersLijst") || {};
msg.payload = Object.values(spelersLijst).map(naam => ({
    naam: naam,
    gepauzeerd: gp[naam] === true
}));
return msg;

const bevestigd = global.get("stop_bevestigd") === true;
if (!bevestigd) {
    msg.payload = "GEBLOKKEERD - zet eerst 'Bevestig stop' aan (stap 1).";
    return [msg, null];
}
global.set("spelToestand", "gestopt");
global.set("pofActief", false);
global.set("pofFase", "idle");
global.set("stop_bevestigd", false);
global.set("pofEventenRonde", 0);
msg.payload = "Spel GESTOPT. Levensuren en levensdagen blijven bewaard.";
return [msg, { payload: false }, { payload: "Gestopt" }, { payload: "Events deze ronde: 0" }, { payload: "—" }];

const actief = global.get("pofActief") === true;
const fase   = global.get("pofFase") || "idle";
const event  = global.get("pofHuidigEvent") || {};
const teller = global.get("pofTeller") ?? null;
const maxT   = global.get("pofTellerMax") ?? null;
const ver    = global.get("pofVerificatie") || {};

msg.payload = {
    actief,
    fase,
    eventNaam:   event.naam || "",
    eventTekst:  event.tekstIngevuld || "",
    doelwit:     ver.doelwit || [],
    getalWaarde: event.getalWaarde ?? null,
    teller,
    maxTeller: maxT
};
msg.topic = "pof/status";
return msg;

const p = msg.payload;
if (!p || !Array.isArray(p.doelwit)) return null;
msg.payload = p.doelwit.length
    ? p.doelwit.map(d => "• " + d).join("\n")
    : "(niemand)";
return msg;
